'use strict'

// Simulates old-style function constructor where a query method is
// assigned as an arrow-function instance property (as in mariadb v2).
function Foo (opts) {
  this.opts = opts

  this.test = () => {}
}

function test () {
  const foo = new Foo({ host: 'localhost' })
  foo.test('SELECT 1')
}

module.exports = { test }
